INSERT INTO support_measures (code, title, short_description, full_description, category, level, amount_text, frequency, min_children, requires_low_income, requires_many_children, requires_pregnancy, requires_single_parent, requires_disability, requires_military_family, requires_student, requires_mortgage, child_age_min, child_age_max, apply_url, legal_source, icon, priority, deadline_text) VALUES
('matkapital_first', 'Материнский капитал на первого ребёнка', 'Сертификат на 630 380 ₽ при рождении первого ребёнка', 'Государственная поддержка семей при рождении или усыновлении первого ребёнка с 1 января 2020 года. Можно направить на жильё, образование детей, накопительную пенсию матери, ежемесячные выплаты, реабилитацию ребёнка-инвалида.', 'financial', 'federal', '630 380 ₽ единовременно', 'one_time', 1, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 18, 'https://www.gosuslugi.ru/10058', 'ФЗ № 256-ФЗ от 29.12.2006', 'Baby', 100, 'Нет ограничений по сроку обращения'),
('matkapital_second', 'Материнский капитал на второго ребёнка', 'Сертификат на 833 024 ₽ при рождении второго ребёнка', 'Если на первого ребёнка маткапитал не получали — выдаётся 833 024 ₽. Если получали — доплата 202 643 ₽.', 'financial', 'federal', '833 024 ₽ или доплата 202 643 ₽', 'one_time', 2, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 18, 'https://www.gosuslugi.ru/10058', 'ФЗ № 256-ФЗ от 29.12.2006', 'Baby', 100, 'Нет ограничений по сроку обращения'),
('single_benefit', 'Единое пособие на детей и беременных', 'Ежемесячная выплата от 50% до 100% прожиточного минимума', 'Назначается семьям с доходом ниже прожиточного минимума на ребёнка до 17 лет и беременным женщинам, вставшим на учёт до 12 недель.', 'financial', 'federal', '7 000 – 16 000 ₽/мес в зависимости от региона', 'monthly', 0, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 17, 'https://www.gosuslugi.ru/600323', 'ФЗ № 81-ФЗ', 'Wallet', 95, 'Подавать ежегодно'),
('family_mortgage', 'Семейная ипотека под 6%', 'Льготная ипотечная ставка для семей с детьми', 'Ставка 6% годовых на покупку жилья на первичном рынке для семей, в которых после 01.01.2018 родился ребёнок. Для ДФО, новых регионов и семей с ребёнком-инвалидом — 5%.', 'housing', 'federal', 'Ставка от 5% до 6% годовых', 'one_time', 1, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 18, 'https://xn--d1aqf.xn--p1ai/', 'Постановление Правительства РФ № 1711', 'Home', 90, 'Программа продлена до 2030 года'),
('many_children_450k', 'Выплата 450 000 ₽ многодетным на ипотеку', 'Государство гасит до 450 000 ₽ ипотечного долга', 'Семьи, в которых с 01.01.2019 по 31.12.2030 родился третий или последующий ребёнок, получают компенсацию ипотечного кредита до 450 тыс. рублей.', 'housing', 'federal', 'до 450 000 ₽ единовременно', 'one_time', 3, FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, 0, 18, 'https://дом.рф/multikids/', 'ФЗ № 157-ФЗ от 03.07.2019', 'Home', 88, 'До конца 2030 года'),
('pregnancy_benefit', 'Пособие по беременности и родам', 'Декретные выплаты работающим женщинам', 'Выплачивается за 140 дней (70 до родов и 70 после) в размере 100% среднего заработка. Для безработных — фиксированно.', 'financial', 'federal', '100% среднего заработка за 140 дней', 'one_time', 0, FALSE, FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, NULL, 'https://www.gosuslugi.ru/600365', 'ФЗ № 255-ФЗ', 'HeartPulse', 85, 'Подавать в течение 6 месяцев после окончания декрета'),
('birth_lumpsum', 'Единовременное пособие при рождении', 'Выплата при рождении каждого ребёнка', 'Получает один из родителей независимо от занятости. Сумма ежегодно индексируется.', 'financial', 'federal', '24 604 ₽ (с 01.02.2025)', 'one_time', 1, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 0, 'https://www.gosuslugi.ru/600370', 'ФЗ № 81-ФЗ', 'Gift', 92, 'В течение 6 месяцев со дня рождения'),
('child_care_15', 'Пособие по уходу до 1.5 лет', 'Ежемесячная выплата 40% от заработка', 'Получает мать, отец или другой родственник, фактически осуществляющий уход. Минимум — фиксированная сумма для безработных.', 'financial', 'federal', '40% заработка, мин. 9 227 ₽', 'monthly', 1, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 1, 'https://www.gosuslugi.ru/600373', 'ФЗ № 81-ФЗ', 'Heart', 90, 'Подать в течение 6 месяцев'),
('early_pregnancy', 'Пособие при ранней постановке на учёт', 'Выплата беременным до 12 недель', 'Беременные с доходом ниже прожиточного минимума, вставшие на учёт до 12 недель — получают 50–100% ПМ ежемесячно. Включено в Единое пособие.', 'financial', 'federal', '50–100% прожиточного минимума', 'monthly', 0, TRUE, FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, NULL, 'https://www.gosuslugi.ru/600323', 'ФЗ № 81-ФЗ', 'Baby', 80, 'До родов'),
('many_children_status', 'Статус многодетной семьи', 'Удостоверение многодетной семьи', 'Даёт право на льготы: бесплатный проезд, питание в школе, лекарства до 6 лет, льготы по ЖКХ, земельный участок, налоговые льготы.', 'status', 'federal', 'Пакет льгот', 'permanent', 3, FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 18, 'https://www.gosuslugi.ru/600351', 'Указ Президента РФ № 63 от 23.01.2024', 'Award', 95, 'Бессрочно'),
('many_children_school_meals', 'Бесплатное питание в школе для многодетных', 'Двухразовое питание для детей из многодетных семей', 'Многодетные семьи имеют право на бесплатное двухразовое горячее питание для школьников.', 'education', 'federal', 'Бесплатно', 'monthly', 3, FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 6, 18, 'https://www.gosuslugi.ru/', 'Указ Президента № 63', 'Utensils', 70, 'На время обучения'),
('many_children_meds', 'Бесплатные лекарства до 6 лет', 'Лекарства по рецепту врача для детей до 6 лет', 'Дети до 6 лет из многодетных семей получают лекарства бесплатно по рецепту.', 'health', 'federal', 'Бесплатно по рецепту', 'permanent', 3, FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 6, NULL, 'Указ Президента № 431', 'Pill', 65, 'До 6 лет ребёнка'),
('many_children_transport', 'Бесплатный проезд для многодетных', 'Бесплатный проезд в общественном транспорте', 'Дети из многодетных семей и один из родителей пользуются городским транспортом бесплатно.', 'transport', 'federal', 'Бесплатно', 'permanent', 3, FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 18, NULL, 'Указ Президента № 431', 'Bus', 60, 'На время статуса'),
('school_uniform', 'Компенсация за школьную форму многодетным', 'Ежегодная выплата на форму', 'В большинстве регионов РФ многодетные получают компенсацию или выплату на покупку школьной формы.', 'education', 'federal', '2 000 – 12 000 ₽ в зависимости от региона', 'yearly', 3, FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 6, 18, NULL, 'Региональные акты + Указ № 431', 'Shirt', 55, 'Раз в год к 1 сентября'),
('tax_deduction_child', 'Стандартный вычет НДФЛ на ребёнка', 'Уменьшение налоговой базы родителей', 'Родителям ежемесячно уменьшают налогооблагаемый доход: на 1-го и 2-го — 1 400 ₽, на 3-го и далее — 3 000 ₽, на ребёнка-инвалида — 12 000 ₽.', 'tax', 'federal', '1 400 – 12 000 ₽/мес уменьшения базы', 'monthly', 1, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 24, 'https://www.nalog.gov.ru/', 'НК РФ ст. 218', 'Receipt', 75, 'Ежегодно через работодателя'),
('tax_deduction_education', 'Налоговый вычет на обучение детей', 'Возврат 13% от расходов на обучение', 'Возврат НДФЛ за обучение ребёнка до 24 лет. Лимит — 110 000 ₽ в год на каждого ребёнка (с 2024).', 'tax', 'federal', 'до 14 300 ₽ в год на ребёнка', 'yearly', 1, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 24, 'https://www.nalog.gov.ru/', 'НК РФ ст. 219', 'GraduationCap', 70, 'В течение 3 лет после оплаты'),
('tax_deduction_med', 'Налоговый вычет на лечение детей', 'Возврат 13% от расходов на лечение и лекарства', 'Возврат НДФЛ за медуслуги, лекарства по рецепту, ДМС. Лимит — 150 000 ₽/год (с 2024).', 'tax', 'federal', 'до 19 500 ₽ в год', 'yearly', 1, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 18, 'https://www.nalog.gov.ru/', 'НК РФ ст. 219', 'Stethoscope', 65, 'В течение 3 лет'),
('preschool_compensation', 'Компенсация за детский сад', 'Возврат части родительской платы', 'На 1-го ребёнка — 20%, на 2-го — 50%, на 3-го и далее — 70% от средней платы за детский сад.', 'education', 'federal', '20–70% платы за сад', 'monthly', 1, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 1, 7, 'https://www.gosuslugi.ru/', 'ФЗ № 273-ФЗ ст. 65', 'School', 70, 'Подаётся при зачислении в сад'),
('school_meals_1_4', 'Бесплатное горячее питание 1–4 классов', 'Завтрак или обед для всех младшеклассников', 'С 2020 года все ученики начальной школы получают бесплатное горячее питание независимо от дохода семьи.', 'education', 'federal', 'Бесплатно', 'monthly', 1, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 6, 11, NULL, 'ФЗ № 47-ФЗ от 01.03.2020', 'Apple', 80, 'На время обучения 1-4 кл.'),
('disability_child_pension', 'Социальная пенсия ребёнку-инвалиду', 'Ежемесячная выплата ребёнку с инвалидностью', 'Социальная пенсия + ежемесячная денежная выплата (ЕДВ) + набор социальных услуг.', 'disability', 'federal', '~22 000 ₽/мес (пенсия + ЕДВ)', 'monthly', 1, FALSE, FALSE, FALSE, FALSE, TRUE, FALSE, FALSE, FALSE, 0, 18, 'https://sfr.gov.ru/', 'ФЗ № 166-ФЗ', 'HeartHandshake', 95, 'На срок инвалидности'),
('disability_caregiver', 'Выплата по уходу за ребёнком-инвалидом', 'Ежемесячная выплата неработающему родителю', 'Родителю или опекуну ребёнка-инвалида, не работающему и осуществляющему уход — 10 000 ₽/мес.', 'disability', 'federal', '10 000 ₽/мес', 'monthly', 1, FALSE, FALSE, FALSE, FALSE, TRUE, FALSE, FALSE, FALSE, 0, 18, 'https://sfr.gov.ru/', 'Указ Президента № 175 от 26.02.2013', 'HeartHandshake', 90, 'На время ухода'),
('military_family_payments', 'Выплаты семье участника СВО', 'Региональные и федеральные меры поддержки семей мобилизованных и контрактников', 'Включают: ежемесячные выплаты, льготы по ЖКХ, бесплатное питание в школе, бесплатные кружки, психологическую помощь, помощь в трудоустройстве супруги, льготную ипотеку.', 'military', 'federal', 'Пакет мер', 'monthly', 0, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, FALSE, FALSE, 0, 18, 'https://sfr.gov.ru/', 'Указ Президента № 98 от 17.02.2023', 'Shield', 95, 'На период службы'),
('military_kindergarten', 'Первоочередное место в детсаду для детей участников СВО', 'Внеочередное зачисление в детский сад', 'Дети мобилизованных и контрактников получают место в детсаду в первоочередном порядке.', 'education', 'federal', 'Первоочередно', 'one_time', 1, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, FALSE, FALSE, 1, 7, 'https://www.gosuslugi.ru/', 'Указ Президента № 98', 'School', 75, 'При наличии статуса'),
('student_family', 'Социальная стипендия и выплаты студенческой семье', 'Меры поддержки студентов с детьми', 'Социальная стипендия, материальная помощь, академический отпуск с сохранением выплат, общежитие в приоритете.', 'student', 'federal', 'От 3 600 ₽/мес и пакет льгот', 'monthly', 1, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, TRUE, FALSE, 0, 18, NULL, 'ФЗ № 273-ФЗ', 'GraduationCap', 70, 'На период обучения'),
('childcare_unemployed', 'Пособие безработным по уходу до 1.5 лет', 'Минимальная выплата неработающим родителям', 'Если родитель не работал и не получал декретные — он получает фиксированное минимальное пособие по уходу до 1.5 лет.', 'financial', 'federal', '9 227 ₽/мес (минимум)', 'monthly', 1, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 1, 'https://www.gosuslugi.ru/', 'ФЗ № 81-ФЗ', 'Heart', 75, 'До 1.5 лет ребёнка'),
('housing_subsidy', 'Жилищная субсидия молодой семье', 'Программа Молодая семья — субсидия на жильё', 'Семьи до 35 лет получают субсидию 30–35% от стоимости жилья на покупку или строительство.', 'housing', 'federal', '30–35% стоимости жилья', 'one_time', 0, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, NULL, 'https://молодая-семья.рф/', 'Постановление № 1050', 'Home', 80, 'Подаётся в местной администрации'),
('many_children_land', 'Бесплатный земельный участок многодетным', 'Земля под ИЖС или ЛПХ', 'Многодетные семьи имеют право на бесплатный земельный участок размером от 6 до 15 соток. Реализация — на уровне региона.', 'housing', 'federal', 'Участок 6–15 соток', 'one_time', 3, FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 18, NULL, 'ФЗ № 138-ФЗ', 'Map', 75, 'Очередь региональная'),
('preferential_loans_kids', 'Списание долгов ИП и самозанятым с детьми', 'Частичное списание налогов многодетным предпринимателям', 'В отдельных регионах действуют льготы по налогу на УСН/самозанятость для многодетных предпринимателей.', 'tax', 'federal', 'Зависит от региона', 'yearly', 3, FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 18, NULL, 'Региональные акты', 'Briefcase', 40, 'Раз в год'),
('orphan_payments', 'Выплаты опекунам и приёмным семьям', 'Ежемесячные выплаты на содержание ребёнка под опекой', 'Опекуны и приёмные родители получают ежемесячные выплаты на содержание ребёнка + вознаграждение приёмному родителю.', 'guardianship', 'federal', '12 000 – 25 000 ₽/мес', 'monthly', 1, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 18, NULL, 'ФЗ № 48-ФЗ', 'HeartHandshake', 85, 'До совершеннолетия'),
('adoption_lumpsum', 'Единовременное пособие при усыновлении', 'Выплата при усыновлении ребёнка', 'При усыновлении выплачивается то же пособие, что при рождении — 24 604 ₽. При усыновлении ребёнка-инвалида, старше 7 лет, братьев/сестёр — 187 996 ₽.', 'guardianship', 'federal', '24 604 ₽ или 187 996 ₽', 'one_time', 1, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 18, 'https://www.gosuslugi.ru/', 'ФЗ № 81-ФЗ', 'Gift', 80, 'В течение 6 месяцев'),
('preg_meal_support', 'Питание беременных и кормящих', 'Бесплатное питание для беременных, кормящих и детей до 3 лет', 'Полноценное питание по заключению врача — для беременных, кормящих матерей и детей до 3 лет из малообеспеченных семей.', 'health', 'federal', 'Бесплатно (по заключению)', 'monthly', 0, TRUE, FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, 3, NULL, 'ФЗ № 323-ФЗ ст. 52', 'Apple', 60, 'По заключению врача'),
('child_camp', 'Бесплатные путёвки в детский лагерь', 'Путёвки в оздоровительные лагеря для детей', 'Многодетные, малоимущие и СВО — получают бесплатные путёвки в детские оздоровительные лагеря в каникулы.', 'leisure', 'federal', 'Бесплатно', 'yearly', 1, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 7, 17, NULL, 'Региональные акты', 'Tent', 55, 'Подавать заранее, сезон'),
('pf_certificate_max_use', 'Сертификат ПФДО (Пушкинская карта детям)', 'Финансирование кружков и секций', 'Каждый ребёнок 5–17 лет имеет право на бесплатные кружки и секции через сертификат дополнительного образования.', 'education', 'federal', 'Бесплатные кружки/секции', 'yearly', 1, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 5, 17, NULL, 'ФЗ № 273-ФЗ', 'Sparkles', 65, 'Каждый учебный год'),
('pushkin_card', 'Пушкинская карта (14–22 года)', '5 000 ₽ в год на культурные мероприятия', 'Молодые люди от 14 до 22 лет получают карту с 5 000 ₽/год на музеи, театры, концерты, кино.', 'leisure', 'federal', '5 000 ₽/год', 'yearly', 0, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 14, 22, 'https://www.gosuslugi.ru/pushkincard', 'Постановление № 1521', 'Ticket', 70, 'Каждый год'),
('alimony_state', 'Выплата на детей единственных родителей', 'Поддержка одиноких родителей', 'Включена в Единое пособие. Также — ускоренное взыскание алиментов через ФССП.', 'financial', 'federal', '50–100% ПМ', 'monthly', 1, TRUE, FALSE, FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, 0, 17, 'https://www.gosuslugi.ru/', 'ФЗ № 81-ФЗ', 'User', 75, 'Подаётся ежегодно'),
('father_capital', 'Отцовский капитал в регионах', 'Региональные выплаты отцам многодетных семей', 'В ряде регионов (Приморье, Ульяновская обл., и др.) действует отцовский капитал — единовременная выплата отцу 3+ детей.', 'financial', 'regional', '50 000 – 1 000 000 ₽', 'one_time', 3, FALSE, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, 0, 18, NULL, 'Региональные акты', 'User', 50, 'Зависит от региона'),
('gas_connection', 'Социальная газификация', 'Бесплатное подведение газа к дому', 'Бесплатно подводится газовая труба к границе участка для домов в газифицированных населённых пунктах.', 'housing', 'federal', 'Бесплатно (до участка)', 'one_time', 0, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, NULL, 'https://www.gosuslugi.ru/600373', 'Постановление № 1547', 'Flame', 60, 'Бессрочно'),
('utilities_subsidy', 'Субсидия на оплату ЖКХ', 'Компенсация при доле ЖКХ выше 22% дохода', 'Если расходы на ЖКХ превышают 22% дохода семьи (в ряде регионов — меньше) — государство компенсирует разницу.', 'housing', 'federal', 'Компенсация разницы', 'monthly', 0, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, NULL, 'https://www.gosuslugi.ru/600172', 'ЖК РФ ст. 159', 'Home', 70, 'Подаётся раз в 6 месяцев'),
('social_contract', 'Социальный контракт', 'До 350 000 ₽ на развитие или трудоустройство', 'Малоимущим семьям — соцконтракт на: поиск работы (до 4 ПМ), бизнес ИП/самозанятость (до 350 000 ₽), личное подсобное хозяйство (до 200 000 ₽), обучение (до 30 000 ₽).', 'financial', 'federal', 'до 350 000 ₽ единовременно', 'one_time', 0, TRUE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, FALSE, NULL, NULL, 'https://www.gosuslugi.ru/600335', 'ФЗ № 178-ФЗ', 'Briefcase', 90, 'Раз в год');